    # RED: Fails until Get-ComplianceReport is implemented.
    BeforeAll {
        $script:manifestPath   = Join-Path $PSScriptRoot ".." "fixtures" "package.json"
        $script:configPath     = Join-Path $PSScriptRoot ".." "config" "license-config.json"
