            -ConfigPath $script:configPath -MockLicensesPath $script:mockLicensePath
        $entry = $report[0]
        $entry.PSObject.Properties.Name | Should -Contain "Name"
        $entry.PSObject.Properties.Name | Should -Contain "Version"
